#include<bits/stdc++.h>
using namespace std;
int len(int x){
	int i=0,l=0;
	if(x<0)l=1;
	while(pow(10,i)<=abs(x))i++;
	return i+l;
}
int f(string s){
	int sum=0,len=s.size(),i=0;
	while(len--){
		sum=sum*10+int(s[i]-'0');
		i++;
	}
	return sum;
}
void Stringsplit(string str,const char split,vector<string>& rst){
	istringstream iss(str);
	string token;
	while(getline(iss,token,split))
	{
		rst.push_back(token);
	}
}
int main(void){
	string s;
	char x,C[3]={'+','-','*'};int N,n,m,ans;
	cin>>N;
	getline(cin,s);
	for(int i=0;i<N;i++){
		cout<<endl;
		getline(cin,s);
		vector<string> a;
		Stringsplit(s,' ',a);
		if(a.size()==3)x=C[int(a[0][0]-'a')],n=f(a[1]),m=f(a[2]);
		else if(a.size()==2)n=f(a[0]),m=f(a[1]);
		switch(x){
			case('+'):ans=n+m;break;
			case('-'):ans=n-m;break;
			case('*'):ans=n*m;break;
		}
		cout<<n<<x<<m<<'='<<ans<<endl;
		cout<<len(n)+1+len(m)+1+len(ans)<<endl;
	}
	return false;
}
